import { getOrderDetailApi, type OrderDetailRequestDto } from '../api/orderDetail.api';
import { getOrderDetailFromResponse } from '../repository/orderDetail.repository';
import { useRootStore } from '../..';
import {
  OrderDetailStatus,
} from '../models/orderDetail.model';
import { eventServerResponse } from '~/constants/functions';
import { getParticipantIdFromToken } from '../utils';

interface GetOrderDetailPayload {
  transactionId: string;
  participantId?: string;
}

function handleOrderDetailSuccess(
  orderDetail: ReturnType<typeof getOrderDetailFromResponse>,
  transactionId: string,
): void {
  const { orderDetailActions } = useRootStore.getState();

  if (orderDetail) {
    orderDetailActions.setOrderDetail(orderDetail, transactionId);
    eventServerResponse('ORDER_DETAIL_SUCCESS');
  } else {
    handleOrderDetailError();
  }
}

function handleOrderDetailError(): void {
  const { orderDetailActions } = useRootStore.getState();
  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.ERROR);
  eventServerResponse('ORDER_DETAIL_ERROR');
}

export async function getOrderDetail(
  payload: GetOrderDetailPayload,
): Promise<void> {
  const { orderDetailActions, orderDetail } = useRootStore.getState();

  const isDifferentTransaction = orderDetail.transactionId !== payload.transactionId;
  const isAlreadyLoading = orderDetail.status === OrderDetailStatus.LOADING;

  if (isAlreadyLoading && !isDifferentTransaction) {
    return;
  }

  if (isDifferentTransaction) {
    orderDetailActions.reset();
  }

  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.LOADING);

  try {
    const participantId =
      payload?.participantId ?? (await getParticipantIdFromToken());

    if (!participantId) {
      handleOrderDetailError();
      return;
    }

    const requestPayload: OrderDetailRequestDto = {
      transactionId: payload.transactionId,
      participantId,
    };

    const response = await getOrderDetailApi(requestPayload);
    const orderDetailData = getOrderDetailFromResponse(response);

    if (orderDetailData) {
      handleOrderDetailSuccess(orderDetailData, payload.transactionId);
      return;
    }

    handleOrderDetailError();
  } catch {
    handleOrderDetailError();
  }
}

import type { StateCreator } from 'zustand';
import {
  OrderDetailStatus,
  type OrderDetailState,
  type PointsTransaction,
} from '../models/orderDetail.model';

export interface OrderDetailActions {
  setOrderDetailStatus: (status: OrderDetailStatus) => void;
  setOrderDetail: (orderDetail: PointsTransaction, transactionId?: string) => void;
  reset: () => void;
}

export interface OrderDetailSlice {
  orderDetail: OrderDetailState;
  orderDetailActions: OrderDetailActions;
}

const INITIAL_ORDER_DETAIL_STATE: OrderDetailState = {
  orderDetail: undefined,
  status: OrderDetailStatus.IDLE,
  error: undefined,
  transactionId: undefined,
};

export const createOrderDetailSlice: StateCreator<
  OrderDetailSlice,
  [],
  [],
  OrderDetailSlice
> = (set) => ({
  orderDetail: INITIAL_ORDER_DETAIL_STATE,
  orderDetailActions: {
    setOrderDetailStatus: (status) =>
      set((state) => ({
        orderDetail: { ...state.orderDetail, status },
      })),
    setOrderDetail: (orderDetail, transactionId) =>
      set((state) => ({
        orderDetail: {
          ...state.orderDetail,
          orderDetail,
          status: OrderDetailStatus.SUCCESS,
          error: undefined,
          transactionId,
        },
      })),
    reset: () =>
      set({
        orderDetail: INITIAL_ORDER_DETAIL_STATE,
      }),
  },
});

import { PointsTransaction } from './extract.model';

export enum OrderDetailStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface OrderDetailState {
  orderDetail?: PointsTransaction;
  status: OrderDetailStatus;
  error?: string;
  transactionId?: string;
}

import { api } from '@semparar/mf-app-user';
import type { AxiosResponse } from 'axios';

export interface OrderDetailItemDto {
  id: string;
  unitaryValue: number;
  quantity: number;
  description: string;
}

export interface OrderDetailBenefitDto {
  id: string;
  type: string;
  value: number;
  description: string;
}

export interface MarketplaceItemDto {
  name: string;
  quantity: number;
  valuePoints: number;
  imageUrl?: string;
}

export interface MarketplaceOrderDto {
  vendor?: string;
  items?: MarketplaceItemDto[];
}

export interface MarketplacePaymentDto {
  paymentType: string;
}

export interface MarketplaceDto {
  orders?: MarketplaceOrderDto[];
  payments?: MarketplacePaymentDto[];
  shippingValuePoints?: number;
  valuePoints?: number;
}

export interface OrderDetailDataDto {
  id: string;
  date: string;
  description: string;
  amount: number;
  items: OrderDetailItemDto[];
  benefits: OrderDetailBenefitDto[];
  attributes: any[];
  marketplace?: MarketplaceDto;
}

export interface OrderDetailRequestDto {
  transactionId: string;
  participantId: string;
}

export interface OrderDetailApiResponse {
  data: OrderDetailDataDto;
  status: {
    returnCode: number;
    message: string;
    httpStatus?: number;
  };
}

export async function getOrderDetailApi(
  payload: OrderDetailRequestDto,
): Promise<AxiosResponse<OrderDetailApiResponse>> {
  return api.post<OrderDetailApiResponse>(
    'fintech/v1/rewardProgram/extract-details',
    {
      transactionId: payload.transactionId,
      participantId: payload.participantId,
    },
  );
}

import { PointsTransaction } from '../models/extract.model';
import type { OrderDetailDataDto, getOrderDetailApi } from '../api/orderDetail.api';

function getTransactionFromOrderDetail(dto: OrderDetailDataDto): PointsTransaction {
  const items = dto.items || [];
  const benefits = dto.benefits || [];

  const totalValue = items.reduce((sum, item) => sum + (item.unitaryValue * item.quantity), 0);

  const fields: Array<{ label: string; value: string }> = [];

  if (items.length > 0) {
    items.forEach((item, index) => {
      fields.push({
        label: `Item ${index + 1}`,
        value: `${item.description} - ${item.quantity}x R$ ${item.unitaryValue.toFixed(2)}`,
      });
    });
  }

  if (benefits.length > 0) {
    benefits.forEach((benefit, index) => {
      fields.push({
        label: `Benefício ${index + 1}`,
        value: `${benefit.description} - R$ ${Math.abs(benefit.value).toFixed(2)}`,
      });
    });
  }

  return {
    id: dto.id,
    date: dto.date,
    description: dto.description,
    type: 'RESCUE',
    amount: dto.amount,
    currencyValue: totalValue > 0 ? totalValue : Math.abs(dto.amount),
    icon: 'icon-cashback',
    details: {
      provider: 'Cashback',
      extraInfo: '',
      fields,
    },
    status: '',
    marketplace: dto.marketplace,
  };
}

export function getOrderDetailFromResponse(
  response: Awaited<ReturnType<typeof getOrderDetailApi>>,
): PointsTransaction | null {
  const apiResponse = response?.data;

  if (!apiResponse) {
    return null;
  }

  const status = apiResponse.status;
  const returnCode = status?.returnCode;

  if (returnCode !== 200 && returnCode !== 0) {
    return null;
  }

  const orderDetailData = apiResponse.data;

  if (!orderDetailData) {
    return null;
  }

  return getTransactionFromOrderDetail(orderDetailData);
}
